import sys

def main():
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
    except StopIteration:
        return
    tokens = [next(it) for _ in range(n)]
    stack = []
    operators = set(['+', '-', '*', '/', '^'])
    for tok in tokens:
        if tok in operators:
            # binary operator: pop right then left
            right = stack.pop()
            left = stack.pop()
            stack.append(' '.join([tok, left, right]))
        else:
            stack.append(tok)
    # final prefix expression
    if stack:
        sys.stdout.write(stack[-1])

if __name__ == "__main__":
    main()

