#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    vector<string> tokens(n);
    for(int i=0;i<n;++i) cin>>tokens[i];
    vector<string> st;
    const unordered_set<string> ops={"+","-","*","/","^"};
    for(const string &tok:tokens){
        if(ops.count(tok)){
            string right=st.back(); st.pop_back();
            string left=st.back(); st.pop_back();
            st.push_back(tok+" "+left+" "+right);
        }else{
            st.push_back(tok);
        }
    }
    if(!st.empty()) cout<<st.back();
    return 0;
}
